SELECT * FROM store_sales, household_demographics, time_dim, store WHERE ss_sold_time_sk = time_dim.t_time_sk AND ss_hdemo_sk = household_demographics.hd_demo_sk AND ss_store_sk = s_store_sk AND time_dim.t_hour = 8 AND time_dim.t_minute >= 30 AND store.s_store_name = "ese" AND time_dim.t_hour = 9 AND time_dim.t_minute < 30 AND time_dim.t_hour = 10 AND time_dim.t_hour = 11 AND time_dim.t_hour = 12;
